/** Minimal 4x4 solid red JPEG. */
export const JPEG_4x4 = new Uint8Array(
	Buffer.from(
		"",
		"base64",
	),
);

/** Minimal 4x4 solid red PNG. */
export const PNG_4x4 = new Uint8Array(
	Buffer.from(
		"",
		"base64",
	),
);

/** 1x1 transparent GIF — image-size parses dimensions, but blurhash does not support GIF. */
export const GIF_1x1 = new Uint8Array(
	Buffer.from("R0lGODlhAQABAIAAAAAAAP///yH5BAEAAAAALAAAAAABAAEAAAIBRAA7", "base64"),
);
